import{c as t,S as r,j as a,m as s}from"./chunks/framework.DvQr6YbT.js";const g=JSON.parse('{"title":"Grant Access","description":"","frontmatter":{},"headers":[],"relativePath":"sharing/grant-access.md","filePath":"sharing/grant-access.md","lastUpdated":1783414742000}'),o={name:"sharing/grant-access.md"};function n(i,e,h,d,c,l){return r(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="grant-access" tabindex="-1">Grant Access <a class="header-anchor" href="#grant-access" aria-label="Permalink to “Grant Access”">​</a></h1><p><strong>Publishing does not grant access.</strong> A release in a private repo is invisible to anyone without read permission — GitHub answers 404 and doesn&#39;t even confirm the repo exists. Every publish therefore ends with an <em>audience statement</em> telling you who can install; this page is the &quot;how to change that&quot; companion.</p><table tabindex="0"><thead><tr><th>Where the bundle lives</th><th>Who can install</th><th>How to grant access</th></tr></thead><tbody><tr><td>Private repo in your <strong>organization</strong></td><td>Members with read access</td><td>Org base permission Read covers everyone; finer scoping via org teams</td></tr><tr><td>Your <strong>personal</strong> private repo</td><td>Only you + collaborators</td><td>Repo → Settings → Collaborators → invite (they must accept)</td></tr><tr><td><strong>Public</strong> repo</td><td>Anyone with the link</td><td>Nothing to do — that&#39;s the point, and the risk</td></tr></tbody></table><h2 id="the-org-shelf-recommended-for-teams" tabindex="-1">The org shelf (recommended for teams) <a class="header-anchor" href="#the-org-shelf-recommended-for-teams" aria-label="Permalink to “The org shelf (recommended for teams)”">​</a></h2><p>One private repo under your GitHub organization — say <code>your-org/kb-bundles</code> — with the org&#39;s base permission set to <strong>Read</strong>:</p><ul><li>Every member installs with their own GitHub login; nothing to manage per person or per bundle.</li><li>Access follows membership: joining the org grants it, leaving revokes it.</li><li>Anyone on the team can publish to the same shelf — it becomes the team&#39;s knowledge hub.</li></ul><p>GitHub&#39;s Free plan suffices (unlimited private repos and members).</p><h2 id="the-receiver-s-side" tabindex="-1">The receiver&#39;s side <a class="header-anchor" href="#the-receiver-s-side" aria-label="Permalink to “The receiver&#39;s side”">​</a></h2><p>Access alone isn&#39;t enough — the receiver must also be <em>authenticated</em> when downloading: <code>gh auth login</code> for the CLI path, or a logged-in browser for the manual path. The most common confusion is exactly this: see <a href="./troubleshooting">&quot;the link 404s&quot;</a>.</p>',9)])])}const p=t(o,[["render",n]]);export{g as __pageData,p as default};
